SELECT COUNT(*) 
FROM requests 
WHERE request_status = 'failed';

SELECT services.service_name, requests.request_status 
FROM requests 
INNER JOIN services ON requests.service_id = services.service_id;

SELECT remote_address, COUNT(request_id) as total_requests
FROM requests
GROUP BY remote_address;

SELECT event_type, event_message 
FROM system_events 
WHERE timestamp > '2022-01-01 00:00:00';

SELECT incident_id, timestamp, incident_type
FROM security_incidents
WHERE incident_type LIKE '%failed login%' AND timestamp > datetime('now', '-1 day');

SELECT response_code, method, url
FROM requests
ORDER BY timestamp DESC;

SELECT DISTINCT method
FROM requests
ORDER BY method ASC;

SELECT config_key, config_value 
FROM system_configuration 
WHERE config_id = 5;
